# Auto-generated by dev iter-2 (test-writer dispatch) from docs/dev/acceptance-criteria-20260524-172805.json
# AC ID: AC-03  ac_uid: rating_ux_options_03  type: hook

import re
from pathlib import Path

AC_UID = "rating_ux_options_03"
AC_TYPE = "hook"

CLOSE_MD = Path(__file__).resolve().parents[3] / "commands" / "close.md"


def test_AC_03():
    """
    GIVEN: commands/close.md user rating section is read
    WHEN:  the rating mechanism is inspected
    THEN:  (a) AskUserQuestion is absent; (b) <options> XML present with 6 choices;
           (c) each option has machine-readable value attr; (d) block appears in
           orchestrator's text output (not close-report file); (e) post-option
           contract documents three score-update.sh calls + skip no-op.
    """
    text = CLOSE_MD.read_text()
    # (a) AskUserQuestion absent from rating mechanism (allow only in comments/historical notes — none expected)
    assert "AskUserQuestion" not in text, "AskUserQuestion still present in close.md"
    # (b) <options> block with all 6 choices
    assert "<options>" in text and "</options>" in text, "options XML block missing"
    for label in ("5 stars", "4 stars", "3 stars", "2 stars", "1 star", "Skip"):
        assert label in text, f"option label {label!r} missing"
    # (c) plain-text options (no value= attributes — happy renderer doesn't support them)
    for label in ("5 stars -- Excellent", "4 stars -- Good", "3 stars -- Average",
                  "2 stars -- Below average", "1 star -- Poor", "Skip rating"):
        assert label in text, f"option label {label!r} missing from <options> block"
    # (d) explicit statement that options block is in orchestrator text, not file
    assert re.search(r"orchestrator'?s text", text, re.IGNORECASE), "missing orchestrator-text scoping note"
    # (e) post-option handling: three score-update.sh calls for ba/dev/qa user_rating_<N>
    assert "user_rating_" in text, "post-option score-update event missing"
    assert "--agent ba --event user_rating_" in text
    assert "--agent dev --event user_rating_" in text
    assert "--agent qa --event user_rating_" in text
    # skip no-op
    assert re.search(r'skip.*NO score-update|score-update.*skip', text, re.IGNORECASE | re.DOTALL), \
        "skip no-op contract missing"
